-- aggregate_frames.sql
-- Per-month frame counts (COUNTIF), GenAI/governance filters
-- identical to extract_genai_gov.sql.
-- GENERATED by src/build_query.py — do not hand-edit. Run `python -m src.build_query --write` to refresh.

SELECT
  FORMAT_DATE(
    '%Y-%m',
    PARSE_DATE('%Y%m%d', SUBSTR(CAST(DATE AS STRING), 1, 8))
  ) AS month,

  COUNT(*) AS total_articles,

  -- Frame: innovation_opportunity
