    OR REGEXP_CONTAINS(LOWER(AllNames), r'misinformation|disinformation|deepfake|fake news|synthetic media|manipulation|propaganda|scam|impersonation|information integrity|deepfakes|cloned voice|face swap|fake video|fake image|fake photos|false information|fabricated content|fake content|manipulate|election|elections|fraud|impersonate|voters|authenticity|credibility|watermark|detect ai|ai detector|désinformation|infox|propagande|fausse information|contenu falsifié|manipulation|escroquerie|élection|élections|fraude|authenticité|crédibilité|desinformation|falschinformationen|falschmeldung|gefälschte inhalte|betrug|wahl|wahlen|authentizität|glaubwürdigkeit|desinformación|noticias falsas|información falsa|contenido falso|estafa|elección|elecciones|fraude|autenticidad|credibilidad|disinformazione|notizie false|informazioni false|contenuto falso|truffa|elezione|elezioni|frode|autenticità|credibilità|desinformatie|nepnieuws|valse informatie|nep inhoud|oplichting|verkiezing|verkiezingen|fraude|authenticiteit|geloofwaardigheid|dezinformacja|fałszywe informacje|fałszywa treść|oszustwo|wybory|wybory powszechne|autentyczność|wiarygodność|desinformação|notícias falsas|informação falsa|conteúdo falso|fraude|eleição|eleições|autenticidade|credibilidade|dezinformare|știri false|informații false|conținut fals|propagandă|escrocherie|alegeri|fraudă|autenticitate|credibilitate')
  ) AS frame_misinformation_integrity

FROM `gdelt-bq.gdeltv2.gkg_partitioned`
WHERE DATE(_PARTITIONTIME) >= '2022-11-01'
  AND DATE(_PARTITIONTIME) <= '2026-06-30'

  -- GenAI filter (identical predicate to extract_genai_gov.sql)
  AND (
    REGEXP_CONTAINS(LOWER(AllNames),
      r'chatgpt|generative ai|genai|gen ai|large language model|llm|foundation model|frontier model|gpt-4|gpt4|gpt-4o|gpt4o|gpt-5|gpt5|claude|anthropic|openai|gemini|bard|dall-e|dalle|stable diffusion|midjourney|text-to-image|image generator|copilot|grok|llama|deepseek|sora|mistral ai|ai agent|agentic ai|reasoning model')
    OR
    REGEXP_CONTAINS(LOWER(Quotations),
      r'chatgpt|generative ai|large language model|foundation model|frontier model|anthropic|openai|gpt-4o|deepseek|ai agent|agentic ai|reasoning model|ia générative|intelligence artificielle générative|grand modèle de langage|modèle de langage|modèle de fondation|agent ia|ia agentique|modèle de raisonnement|generative ki|generative künstliche intelligenz|großes sprachmodell|sprachmodell|basismodell|ki-agent|agentische ki|reasoning-modell|ia generativa|inteligencia artificial generativa|modelo de lenguaje grande|modelo de lenguaje|modelo fundacional|agente ia|ia agéntica|modelo de razonamiento|ia generativa|intelligenza artificiale generativa|modello linguistico|modello di linguaggio|modello fondazionale|agente ia|ia agentiva|modello di ragionamento|generatieve ai|generatieve kunstmatige intelligentie|groot taalmodel|taalmodel|basismodel|ai-agent|agentische ai|redeneermodel|generatywna ai|generatywna sztuczna inteligencja|duży model językowy|model językowy|model podstawowy|agent ai|agentyczna ai|model rozumowania|ia generativa|inteligência artificial generativa|grande modelo de linguagem|modelo de linguagem|modelo fundacional|agente ia|ia agêntica|modelo de raciocínio')
)

  -- Governance filter (identical predicate to extract_genai_gov.sql)
  AND (
    REGEXP_CONTAINS(LOWER(Quotations),
      r'governance|regulation|regulatory|regulator|policy|oversight|law|legislation|ai act|eu ai act|framework|guidelines|compliance|enforcement|accountability|liability|responsible ai|trustworthy ai|ethical ai|risk management|guardrails|safeguards|ai safety|human rights|privacy|data protection|misinformation|deepfake|gouvernance|réglementation|régulation|réglementaire|régulateur|politique|surveillance|loi|législation|cadre réglementaire|lignes directrices|conformité|mise en application|reddition de comptes|responsabilité civile|ia responsable|ia digne de confiance|ia éthique|gestion des risques|garde-fous|garanties|sécurité de l'ia|droits humains|droits de l'homme|vie privée|protection des données|désinformation|governance|regulierung|regulatorisch|aufsichtsbehörde|richtlinie|aufsicht|gesetz|gesetzgebung|rechtsrahmen|leitlinien|compliance|durchsetzung|rechenschaftspflicht|haftung|verantwortungsvolle ki|vertrauenswürdige ki|ethische ki|risikomanagement|leitplanken|schutzmaßnahmen|ki-sicherheit|menschenrechte|datenschutz|desinformation|gobernanza|regulación|regulatorio|regulador|política|supervisión|ley|legislación|marco regulatorio|directrices|cumplimiento|aplicación|rendición de cuentas|responsabilidad|ia responsable|ia confiable|ia ética|gestión de riesgos|salvaguardas|salvaguardias|seguridad de la ia|derechos humanos|privacidad|protección de datos|desinformación|governance|regolamentazione|normativo|regolatorio|autorità di regolazione|politica|supervisione|legge|legislazione|quadro normativo|linee guida|conformità|applicazione|responsabilità|ia responsabile|ia affidabile|ia etica|gestione del rischio|salvaguardie|garanzie|sicurezza dell'ia|diritti umani|riservatezza|protezione dei dati|disinformazione|governance|regulering|regelgeving|regelgevend|toezichthouder|beleid|toezicht|wet|wetgeving|kader|richtlijnen|naleving|handhaving|verantwoording|aansprakelijkheid|verantwoorde ai|betrouwbare ai|ethische ai|risicobeheer|vangrails|waarborgen|ai-veiligheid|mensenrechten|privacy|gegevensbescherming|desinformatie|zarządzanie|regulacja|regulacyjny|organ regulacyjny|polityka|nadzór|prawo|ustawodawstwo|ramy prawne|wytyczne|zgodność|egzekwowanie|rozliczalność|odpowiedzialność|odpowiedzialna ai|godna zaufania ai|etyczna ai|zarządzanie ryzykiem|zabezpieczenia|środki ochrony|bezpieczeństwo ai|prawa człowieka|prywatność|ochrona danych|dezinformacja|governança|regulamentação|regulação|regulatório|regulador|política|supervisão|fiscalização|lei|legislação|quadro regulatório|diretrizes|conformidade|aplicação|responsabilização|prestação de contas|ia responsável|ia confiável|ia ética|gestão de riscos|salvaguardas|garantias|segurança da ia|direitos humanos|privacidade|proteção de dados|desinformação|guvernanță|reglementare|regulatorie|autoritate de reglementare|politică|supraveghere|lege|legislație|cadru normativ|orientări|conformitate|aplicare|răspundere|ia responsabilă|siguranța ia|gestionarea riscurilor|garanții|drepturile omului|confidențialitate|viața privată|protecția datelor|dezinformare')
    OR
    REGEXP_CONTAINS(V2Themes,
      r'EPU_CATS_REGULATION|EPU_POLICY_LAW|EPU_POLICY_REGULATION|LEGISLATION|WB_831_GOVERNANCE|WB_845_LEGAL_AND_REGULATORY_FRAMEWORK|WB_279_ICT_STRATEGY_POLICY_AND_REGULATION|WB_282_ICT_POLICY_REGULATORY_FRAMEWORK|WB_2089_ETHICS_AND_CODES_OF_CONDUCT|WB_838_PUBLIC_ACCOUNTABILITY_MECHANISMS|WB_851_INTELLECTUAL_PROPERTY_RIGHTS|HUMAN_RIGHTS|UNGP_POLITICAL_FREEDOMS|UNGP_FREEDOM_FROM_DISCRIMINATION|UNGP_CRIME_VIOLENCE|WB_133_INFORMATION_AND_COMMUNICATION_TECHNOLOGIES|WB_678_DIGITAL_GOVERNMENT|WB_670_ICT_SECURITY|EPU_CATS_NATIONAL_SECURITY|CYBER_ATTACK|WB_840_JUSTICE|WB_1014_CRIMINAL_JUSTICE|TRIAL|WB_2369_DATA_PRIVACY|ELECTION|ELECTION_FRAUD|GENERAL_GOVERNMENT|TAX_FNCACT_REGULATOR')
    OR
    REGEXP_CONTAINS(LOWER(DocumentIdentifier),
      r'-regulat|-policy-|-legislat|-governance-|-safety-|-security-|-threat|-warns-|-warning-|-ethic|-privacy-|-rights-|-oversight-|-copyright|-lawsuit|-banned-|-ban-|-ai-act')
)

GROUP BY month
ORDER BY month;
